function normalizeFaqText(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function faqWordSet(value = "") {
  return new Set(
    normalizeFaqText(value)
      .split(" ")
      .filter((word) => word.length >= 2 && !["the", "and", "for", "you", "how", "what", "does", "with", "this", "that", "can", "use", "why", "are", "is", "do", "to"].includes(word))
  );
}

function scoreFaqMatch(question = "", faq = {}) {
  const q = normalizeFaqText(question);
  const fq = normalizeFaqText(faq.question || "");
  const fa = normalizeFaqText(faq.answer || "");
  const fc = normalizeFaqText(faq.category || "");

  if (!q || !fq) return 0;

  let score = 0;

  if (fq === q) score += 1000;
  if (fq.startsWith(q) || q.startsWith(fq)) score += 650;
  if (fq.includes(q) || q.includes(fq)) score += 520;

  const qWords = faqWordSet(question);
  const faqWords = faqWordSet(`${faq.question || ""} ${faq.category || ""}`);
  const answerWords = faqWordSet(faq.answer || "");

  let exactMatches = 0;
  for (const word of qWords) {
    if (faqWords.has(word)) {
      exactMatches += 1;
      score += 85;
    } else if (answerWords.has(word)) {
      score += 42;
    } else {
      for (const fWord of faqWords) {
        if (fWord.startsWith(word) || word.startsWith(fWord)) {
          score += 35;
          break;
        }
      }
    }
  }

  if (qWords.size > 0 && exactMatches / qWords.size >= 0.7) score += 180;
  if (fc && q.includes(fc)) score += 90;

  return score;
}

function findFaqAnswer(question = "") {
  const q = normalizeFaqText(question);
  if (!q) return null;

  const scored = EVAL_FAQ_SEARCH_DATABASE
    .map((faq) => ({ faq, score: scoreFaqMatch(question, faq) }))
    .filter((entry) => entry.score >= 160)
    .sort((a, b) => b.score - a.score || String(a.faq.question).localeCompare(String(b.faq.question)));

  if (!scored.length) return null;

  const best = scored[0];
  const second = scored[1];

  if (best.score >= 330 || !second || best.score >= second.score + 110) {
    return best.faq.answer;
  }

  return null;
}

function localAssistantAnswer(question = "") {
  const companyAnswer = findTickerLookupAnswer(question);
  if (companyAnswer) {
    return {
      answer: companyAnswer,
      source: "csv",
    };
  }

  const faqAnswer = findFaqAnswer(question);
  if (faqAnswer) {
    return {
      answer: faqAnswer,
      source: "faq",
    };
  }

  return null;
}


function round1(value) {
  const num = Number(value);
  return Number.isFinite(num) ? num.toFixed(1) : "N/A";
}

function assistantPortfolioGroups(portfolio = {}, holdings = []) {
  if (Array.isArray(portfolio?.analysis?.industryGroups) && portfolio.analysis.industryGroups.length) {
    return portfolio.analysis.industryGroups;
  }
  const map = new Map();
  for (const h of holdings || []) {
    const industry = String(h?.industry || h?.finnhubIndustry || "Unknown");
    if (!map.has(industry)) map.set(industry, []);
    map.get(industry).push(h);
  }
  return [...map.entries()].map(([industry, group]) => ({
    industry,
    holdings: group,
    totalWeightPercent: group.reduce((sum, h) => sum + (Number(h?.weightPercent ?? h?.weight) || 0), 0),
    industryEvalScore: (() => {
      const total = group.reduce((sum, h) => sum + (Number(h?.weightPercent ?? h?.weight) || 0), 0);
      if (total <= 0) return null;
      return group.reduce((sum, h) => sum + (Number(h?.edgeScore ?? h?.score) || 0) * ((Number(h?.weightPercent ?? h?.weight) || 0) / total), 0);
    })(),
  })).sort((a,b)=>Number(b.totalWeightPercent||0)-Number(a.totalWeightPercent||0));
}

function assistantTickerToken(question = "", candidates = []) {
  const tokens = [...String(question || "").toUpperCase().matchAll(/\b[A-Z]{1,5}(?:\.[A-Z])?\b/g)].map(m => m[0]);
  const set = new Set(candidates.map(x => String(x || "").toUpperCase()));
  return tokens.find(t => set.has(t)) || tokens[0] || "";
}

function enhancedAssistantContextAnswer(question = "", ctx = {}) {
  const q = String(question || "").trim();
  const lower = q.toLowerCase();
  const current = ctx.current || null;
  const watchlist = Array.isArray(ctx.watchlist) ? ctx.watchlist : [];
  const portfolio = ctx.portfolio || {};
  const holdings = Array.isArray(ctx.portfolioHoldings) ? ctx.portfolioHoldings : [];
  const groups = assistantPortfolioGroups(portfolio, holdings);
  const watchSymbols = watchlist.map(w => cleanTicker(w?.symbol || w?.ticker)).filter(Boolean);
  const holdingSymbols = holdings.map(h => cleanTicker(h?.symbol || h?.ticker)).filter(Boolean);
  const allSymbols = [...new Set([cleanTicker(current?.symbol || current?.profile?.ticker), ...watchSymbols, ...holdingSymbols].filter(Boolean))];
  const token = assistantTickerToken(q, allSymbols);
  const holding = holdings.find(h => cleanTicker(h?.symbol || h?.ticker) === token);
  const watch = watchlist.find(w => cleanTicker(w?.symbol || w?.ticker) === token);
  const currentSymbol = cleanTicker(current?.symbol || current?.profile?.ticker);

  if (/\b(watchlist|saved stocks?)\b/i.test(q)) {
    if (!watchlist.length) return "Your watchlist is empty.";
    if (/\b(highest|best|strongest|top score)\b/i.test(q)) {
      const best = [...watchlist].filter(w => Number.isFinite(Number(w?.edgeScore ?? w?.score))).sort((a,b)=>Number(b.edgeScore ?? b.score)-Number(a.edgeScore ?? a.score))[0];
      return best ? `${cleanTicker(best.symbol || best.ticker)} has the highest watchlist Eval Score at ${round1(best.edgeScore ?? best.score)}.` : "Please try again.";
    }
    return `Watchlist: ${watchlist.slice(0, 12).map(w => cleanTicker(w.symbol || w.ticker)).filter(Boolean).join(", ")}${watchlist.length > 12 ? `, plus ${watchlist.length - 12} more` : ""}.`;
  }

  if (/\b(portfolio|holding|holdings|weight|allocation|industry|sector|trim|reduce|rebalance|strategy)\b/i.test(q) && holdings.length) {
    if (token && holding && /\b(weight|weigh|percent|%)\b/i.test(q)) {
      return `${token} is about ${round1(holding.weightPercent ?? holding.weight)}% of the saved portfolio.`;
    }
    if (/\b(industry|sector).*(weight|allocation)|weight.*(industry|sector)\b/i.test(q)) {
      const top = groups.slice(0, 5).map(g => `${g.industry}: ${round1(g.totalWeightPercent)}%`).join("; ");
      return top ? `Current industry weights: ${top}.` : "Please try again.";
    }
    if (/\b(trim|reduce|lessen|rebalance|overweight|too much|sell)\b/i.test(q)) {
      const targets = portfolio?.strategyTargets || {};
      const rankedGroups = groups.map(g => {
        const target = Number(targets[g.industry]);
        const actual = Number(g.totalWeightPercent || 0);
        const diff = Number.isFinite(target) ? actual - target : actual;
        return { ...g, target, actual, diff };
      }).sort((a,b)=>Number(b.diff||0)-Number(a.diff||0));
      const group = rankedGroups.find(g => Number.isFinite(g.target) ? (g.diff >= 8 || (g.target > 0 && g.actual / g.target >= 1.25)) : g.actual >= 25) || rankedGroups[0];
      if (!group) return "Please try again.";
      const candidates = [...(group.holdings || [])].sort((a,b) => {
        const aw = Number(a.weightPercent ?? a.weight) || 0;
        const bw = Number(b.weightPercent ?? b.weight) || 0;
        const as = Number(a.edgeScore ?? a.score) || 0;
        const bs = Number(b.edgeScore ?? b.score) || 0;
        return (bw - aw) || (as - bs);
      }).slice(0,3).map(h => `${cleanTicker(h.symbol || h.ticker)} (${round1(h.weightPercent ?? h.weight)}%, Eval ${round1(h.edgeScore ?? h.score)})`);
      const targetText = Number.isFinite(group.target) ? ` vs ${round1(group.target)}% target` : "";
      return `${group.industry} is the main trim area at ${round1(group.actual)}%${targetText}. Review: ${candidates.join(", ")}.`;
    }
    if (/\b(highest|largest|biggest)\b/i.test(q)) {
      const top = [...holdings].sort((a,b)=>Number(b.weightPercent ?? b.weight ?? 0) - Number(a.weightPercent ?? a.weight ?? 0))[0];
      return top ? `${cleanTicker(top.symbol || top.ticker)} is the largest holding at about ${round1(top.weightPercent ?? top.weight)}%.` : "Please try again.";
    }
    if (/\b(score|eval)\b/i.test(q) && token && holding) {
      return `${token} has a saved portfolio Eval Score of ${round1(holding.edgeScore ?? holding.score)} and is ${round1(holding.weightPercent ?? holding.weight)}% of the portfolio.`;
    }
  }

  if (/\b(earnings|report date|earnings date)\b/i.test(q)) {
    const events = []
      .concat(Array.isArray(portfolio?.earnings) ? portfolio.earnings : [])
      .concat(Array.isArray(portfolio?.earnings?.events) ? portfolio.earnings.events : [])
      .concat(Array.isArray(portfolio?.analysis?.earnings) ? portfolio.analysis.earnings : [])
      .concat(Array.isArray(portfolio?.analysis?.earnings?.events) ? portfolio.analysis.earnings.events : []);
    const filtered = events.filter(e => !token || cleanTicker(e?.symbol) === token);
    if (filtered.length) {
      const e = filtered[0];
      return `${cleanTicker(e.symbol)} reports earnings on ${e.date || e.period || "the listed calendar date"}. EPS estimate: ${e.epsEstimate ?? e.eps ?? "N/A"}. Revenue estimate: ${e.revenueEstimate ?? e.revenue ?? "N/A"}.`;
    }
    return "Please try again.";
  }

  if (token && (watch || holding || token === currentSymbol)) {
    if (holding) return `${token}: Eval ${round1(holding.edgeScore ?? holding.score)}, weight ${round1(holding.weightPercent ?? holding.weight)}%, industry ${holding.industry || "N/A"}.`;
    if (watch) return `${token}: saved in watchlist with Eval ${round1(watch.edgeScore ?? watch.score)}.`;
    if (token === currentSymbol) return `${token}: loaded report Eval ${round1(current?.grades?.edgeScore)}, price ${current?.quote?.c ?? "N/A"}.`;
  }

  return null;
}



function normalizeIndustryName(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getIndustryKey(industry = "") {
  const clean = normalizeIndustryName(industry);

  for (const [key, terms] of INDUSTRY_ALIASES) {
    if (terms.some((term) => clean.includes(normalizeIndustryName(term)))) {
      return key;
    }
  }

  return Object.keys(INDUSTRY_UNIVERSES).find((key) => normalizeIndustryName(key) === clean) || "Technology";
}

function isValidAnalysisPayload(data) {
  const score = Number(data?.grades?.edgeScore);
  const validCategories = Number(data?.grades?.dataQuality?.validCategoryCount || 0);
  const inputCounts = data?.grades?.dataQuality?.validInputCounts || {};

  const hasEnoughFundamentals =
    Number(inputCounts.growth || 0) >= 2 ||
    Number(inputCounts.profitability || 0) >= 2 ||
    Number(inputCounts.financialHealth || 0) >= 2 ||
    Number(inputCounts.valuation || 0) >= 2;

  const hasMarketData = Number(inputCounts.marketData || 0) >= 2 || Boolean(data?.quote?.c);

  return Number.isFinite(score) && score >= 2 && validCategories >= 5 && hasMarketData && hasEnoughFundamentals;
}

function hoursFromMs(ms) {
  return Number((ms / (60 * 60 * 1000)).toFixed(1));
}

function componentMetaFor(savedAt = {}) {
  return {
    fundamentals: hoursFromMs(COMPONENT_TTLS_MS.fundamentals),
    valuation: hoursFromMs(COMPONENT_TTLS_MS.valuation),
    market: hoursFromMs(COMPONENT_TTLS_MS.market),
    news: hoursFromMs(COMPONENT_TTLS_MS.news),
    risk: hoursFromMs(COMPONENT_TTLS_MS.risk),
    profile: hoursFromMs(COMPONENT_TTLS_MS.profile),
    savedAt,
  };
}

function withCacheInfo(data, cacheInfo, savedAt = {}) {
  return {
    ...data,
    cache: {
      ...(data?.cache || {}),
      ...cacheInfo,
      ttlHours: 24,
      componentTtlsHours: componentMetaFor(savedAt),
    },
  };
}

function isFresh(savedAt, key) {
  const saved = Number(savedAt?.[key] || 0);
  if (!saved) return false;
  return Date.now() - saved < COMPONENT_TTLS_MS[key];
}

function getRefreshPlan(savedAt = {}) {
  return {
    refreshFundamentals: !isFresh(savedAt, "fundamentals"),
    refreshValuation: !isFresh(savedAt, "valuation"),
    refreshMarket: !isFresh(savedAt, "market"),
    refreshNews: !isFresh(savedAt, "news"),
    refreshRisk: !isFresh(savedAt, "risk"),
    refreshProfile: !isFresh(savedAt, "profile"),
  };
}

function allComponentsFresh(plan) {
  return !Object.values(plan).some(Boolean);
}

function scoreToneName(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return "N/A";
  if (n >= 7.5) return "Strong";
  if (n >= 6.5) return "Mixed";
  return "Weak";
}

function scoreText10(score) {
  const n = Number(score);
  return Number.isFinite(n) ? n.toFixed(1) : "N/A";
}

function availableWeightedAverage(values, fallback = null) {
  let total = 0;
  let weight = 0;

  for (const item of values) {
    const score = Number(item?.score);
    const w = Number(item?.weight);
    if (Number.isFinite(score) && Number.isFinite(w) && w > 0) {
      total += score * w;
      weight += w;
    }
  }

  if (weight === 0) return fallback;
  return Math.max(0, Math.min(10, total / weight));
}

function strongestWeakestFromCategories(categories = {}) {
  const entries = Object.entries(categories)
    .map(([key, value]) => [key, Number(value)])
    .filter(([, value]) => Number.isFinite(value));

  const label = (key) =>
    ({
      growth: "Growth",
      profitability: "Profitability",
      financialHealth: "Financial Health",
      valuation: "Valuation",
      momentum: "Momentum",
      reversal: "Pullback",
      newsSentiment: "News Sentiment",
    }[key] || key);

  if (!entries.length) {
    return { strongest: "Not enough category data yet.", weakest: "Not enough category data yet." };
  }

  const strongest = entries.reduce((best, item) => (item[1] > best[1] ? item : best), entries[0]);
  const weakest = entries.reduce((worst, item) => (item[1] < worst[1] ? item : worst), entries[0]);

  return {
    strongest: `${label(strongest[0])} is the strongest category at ${scoreText10(strongest[1])}/10.`,
    weakest: `${label(weakest[0])} is the weakest category at ${scoreText10(weakest[1])}/10.`,
  };
}

